    @Column(name = "city")
    private String city;

    @Column(name = "street")
    private String street;

    @ManyToOne(cascade = {CascadeType.MERGE, CascadeType.REFRESH}, optional = false)
    //设置在address表中的关联字段(外键)
    @JoinColumn(name = "person_id")
    private Person person;

    @Override
