            InputStream is2 = servletConfig.getServletContext().getResourceAsStream("/WEB-INF/classes/jdbc.properties");//读取web应用目录下的/WEB-INF/classes/jdbc.properties文件（编译后会被拷贝到/WEB-INF/classes/下）
        }catch(Exception e){  }
