@RequestMapping("/headerInfo")  
public void headerInfo(@RequestHeader("Accept-Encoding") String encoding, @RequestHeader("Keep-Alive") long keepAlive)  {  
    System.out.println(encoding);
    System.out.println(keepAlive);
} 
```

