        crossDomain: true //让请求头中包含跨域的额外信息，但不会含cookie
    }).then(function(data, status, jqxhr) {
	alert(data)
    });
});
</script>
```

##### 服务器跨域

让服务器来完成跨域资源的请求

通过nginx配置一个代理服务器（域名与domain1相同，端口不同）做跳板机，反向代理访问domain2接口，并且可以顺便修改cookie中domain信息，方便当前域cookie写入，实现跨域登录

```nginx
server {
    listen 81;
    server_name  www.domain1.com;

    location / {
        proxy_pass http://loginservers; #反向代理
        proxy_cookie_domain www.domain2.com www.domain1.com; #修改cookie domain
        index index.html index.htm;

        # 当用webpack-dev-server等中间件代理接口访问nignx时，此时无浏览器参与，故没有同源限制，下面的跨域配置可不启用
        add_header Access-Control-Allow-Origin http://www.domain1.com; #当前端只跨域不带cookie时，可为*
        add_header Access-Control-Allow-Credentials true;
    }
}

# 使用ip_hash方式的负载均衡
upstream loginservers {
    server www.domain2.com:8080;
    server www.domain3.com:8080;
    ip_hash;
}
```

##### 附:Nginx常用配置

**nginx使用**

```nginx
# 启动
nginx -c /etc/nginx/nginx.conf
# 停止
nginx -s stop -c /etc/nginx/nginx.conf
# 重启
nginx -s reload -c /etc/nginx/nginx.conf
```

**匹配规则**

| 字符 | 匹配规则                                                      |
| ---- | ------------------------------------------------------------ |
| `=`  | 精确匹配，不可以使用正则                                       |
| `~`  | 区分大小写的正则匹配                                           |
| `~*` | 不区分大小写的正则匹配                                         |
| `!~` | 以`!`开头表示不匹配，比如`!~`区分大小写不匹配，`!~*`不区分大小写不匹配 |
| `^~` | uri以某个常规字符串开头，不可以使用正则                         |
| `/`  | 通用匹配, 如果没有其它匹配,任何请求都会匹配到                   |
| 空匹配符 | 不写任何匹配规则则匹配以后面的路径开头的地址                 |

匹配规则是：最大前缀匹配（与顺序无关）

对于正则location的匹配规则是：按编辑顺序逐个匹配（与顺序有关）

**文件目录匹配**

| 字符        | 匹配内容             |
| ----------- | -------------------- |
| `-f`、`!-f` | 文件是否存在         |
| `-d`、`!-d` | 目录是否存在         |
| `-e`、`!-e` | 文件或目录是否存在   |
| `-x`、`!-x` | 文件是否存在且可执行 |

常用在if中，比如

```nginx
if (!-f $request_filename) {
	return 404
}
```

**常用正则**

| 字符    | 匹配内容                                      |
| ------- | --------------------------------------------- |
| `.`     | 匹配除换行符以外的任意字符                    |
| `?`     | 重复0次或1次                                  |
| `+`     | 重复1次或更多次                               |
| `*`     | 重复0次或更多次                               |
| `\d`    | 匹配数字                                      |
| `^`     | 匹配字符串的开始                              |
| `$`     | 匹配字符串的结尾                              |
| `{n}`   | 重复n次                                       |
| `{n,}`  | 重复n次或更多次                               |
| `[c]`   | 匹配单个字符c                                 |
| `[a-z]` | 匹配a-z小写字母的任意一个                     |
| `(xxx)` | 分组，后面可以通过`$1`、`$2`...引用分组的内容 |

**内置变量**

```nginx
