监听事件

```java
ViewGroup decorChild;
boolean swipeEnabled = true;
boolean canSwipe = false;
boolean ignoreSwipe = false;
float downX;
float downY;
float lastX;
float currentX;
float currentY;

@Override
public boolean dispatchTouchEvent(@NonNull MotionEvent ev) {
    if (swipeEnabled && !canSwipe && !ignoreSwipe) {
        switch (ev.getAction()) {
            case MotionEvent.ACTION_DOWN:
                downX = ev.getX();
                downY = ev.getY();
                currentX = downX;
                currentY = downY;
                lastX = downX;
                break;
            case MotionEvent.ACTION_MOVE:
                float dx = ev.getX() - downX;
                float dy = ev.getY() - downY;
                if (dx * dx + dy * dy > touchSlop * touchSlop) {
                    if (dy == 0f || Math.abs(dx / dy) > 1) {
                        downX = ev.getX();
                        downY = ev.getY();
                        currentX = downX;
                        currentY = downY;
                        lastX = downX;
                        canSwipe = true;
                        return true;
                    } else {
                        ignoreSwipe = true;
                    }
                }
                break;
        }
    }
    if (ev.getAction() == MotionEvent.ACTION_UP || ev.getAction() == MotionEvent.ACTION_CANCEL) {
        ignoreSwipe = false;
    }
    return super.dispatchTouchEvent(ev);
}

@Override
public boolean onInterceptTouchEvent(MotionEvent ev) {
    return canSwipe || super.onInterceptTouchEvent(ev);
}

@Override
public boolean onTouchEvent(@NonNull MotionEvent event) {
    if (canSwipe) {
        int action = event.getAction();
        switch (action) {
            case MotionEvent.ACTION_DOWN:
                downX = event.getX();
                downY = event.getY();
                currentX = downX;
                currentY = downY;
                lastX = downX;
                break;
            case MotionEvent.ACTION_MOVE:
                currentX = event.getX();
                currentY = event.getY();
                float dx = currentX - lastX;
                if (getContentX() + dx < 0) {
                    decorChild.setX(0);
                } else {
                    decorChild.setX(decorChild.getX() + dx);
                }
                lastX = currentX;
                invalidate();
                break;
            case MotionEvent.ACTION_UP:
            case MotionEvent.ACTION_CANCEL:
                canSwipe = false;
                //回弹
                //...
                break;
            default:
                break;
        }
    }
    return super.onTouchEvent(event);
}
```

